import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"무가치함의 심리학","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/books/무가치함의-심리학.md","filePath":"outta-space/knowledge/books/무가치함의-심리학.md"}'),_={name:"outta-space/knowledge/books/무가치함의-심리학.md"};function n(l,a,i,s,d,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="무가치함의-심리학" tabindex="-1">무가치함의 심리학 <a class="header-anchor" href="#무가치함의-심리학" aria-label="Permalink to &quot;무가치함의 심리학&quot;">​</a></h1><h2 id="_1-핵심-내용" tabindex="-1">1. 핵심 내용 <a class="header-anchor" href="#_1-핵심-내용" aria-label="Permalink to &quot;1. 핵심 내용&quot;">​</a></h2><p>무가치함이 어떤 것인지, 왜 생겨나는지, 어떻게 다스려야 하는지에 대해서 다루는 책이다.</p><h2 id="_2-문체와-가독성" tabindex="-1">2. 문체와 가독성 <a class="header-anchor" href="#_2-문체와-가독성" aria-label="Permalink to &quot;2. 문체와 가독성&quot;">​</a></h2><p>일본에서 쓰인 책이라 번역투가 묻어나는 문장이 많긴 하다. 문장이 뻑뻑한 느낌이라 해야하나?</p><h2 id="_3-저자의-관점과-설득력" tabindex="-1">3. 저자의 관점과 설득력 <a class="header-anchor" href="#_3-저자의-관점과-설득력" aria-label="Permalink to &quot;3. 저자의 관점과 설득력&quot;">​</a></h2><p>저자는 무가치함을 단순히 &#39;싫은 것&#39;, &#39;나쁜 것&#39;으로 치부하지 않는다. 어떻게 내 내면에 무가치함이 생겨났는지 파악하고, 이를 어떻게 다스릴지 함께 고민한다. 방법도 여러 개 제시한다.</p><h2 id="_4-인상-깊은-부분" tabindex="-1">4. 인상 깊은 부분 <a class="header-anchor" href="#_4-인상-깊은-부분" aria-label="Permalink to &quot;4. 인상 깊은 부분&quot;">​</a></h2><p>가장 인상 깊었던 부분은 자기 인생은 자기가 만들어야 한다고 주장하는 부분이었다. 나는 항상 자아를 찾기에만 급급했지,자아를 만들어갈 생각은 못했기 때문이다. 그래서 내가 성장하지 못했는지도 모른다.</p><h2 id="_5-나에게-남은-생각" tabindex="-1">5. 나에게 남은 생각 <a class="header-anchor" href="#_5-나에게-남은-생각" aria-label="Permalink to &quot;5. 나에게 남은 생각&quot;">​</a></h2><p>앞으로 자아를 만들어가는 사람이 되고, 현실을 자각해 살아가는 사람이 되어야겠다. 이런 생각을 하는 것도 신기하네...</p>',11)])])}const u=e(_,[["render",n]]);export{p as __pageData,u as default};
